const planItems = Array.isArray(incomingPlan) && incomingPlan.length ? incomingPlan : defaultPlanItems;

const sourcePriorityByType = {
  'sec-filings': ['sec-filings', 'company-ir', 'major-news'],
  'market-events': ['press-release', 'company-ir', 'major-news'],
  'price-history': ['price-provider', 'exchange-data']
};
const SEC_FORM_PRIORITY = new Set(['8-K', '10-Q', '10-K', '6-K', '20-F']);
const SEC_USER_AGENT = 'StrattonAI/1.0 local research workspace';

function buildSearchQueries(item) {
  const eventCategory = item.event_category;
  const primary = item.primary_ticker ? `${item.primary_ticker} ` : '';
  const related = item.related_ticker || 'related company';
  const relationship = item.relationship_type ? ` ${item.relationship_type}` : '';
  const sourceType = item.suggested_source_type || 'market-events';
  const sourcePriority = sourcePriorityByType[sourceType] ?? ['major-news'];

  return [
    {
      query_text: `${primary}${eventCategory} ${related}${relationship} historical`.trim(),
      source_type: sourcePriority[0],
      priority: 1,
      notes: `Prefer explicit ${eventCategory} evidence tied to ${related}${relationship ? ` via ${relationship}` : ''}.`
    },
    {
      query_text: `${primary}${related} ${eventCategory} announcement press release historical`.trim(),
      source_type: sourcePriority[Math.min(1, sourcePriority.length - 1)],
      priority: 2,
      notes: 'Prefer primary-source announcements or filing-linked source pages.'
    }
  ];
}

function buildBaseSlice(item) {
  return {
    placeholder_example: false,
    source_gap_key: item.source_gap_key,
    priority_rank: item.priority_rank,
    priority_score: item.priority_score ?? item.planner_score ?? null,
    gap_score: item.gap_score ?? item.notes?.audit_gap_score ?? null,
    event_category: item.event_category,
    target_type: item.target_type,
    primary_ticker: item.primary_ticker ?? null,
    related_ticker: item.related_ticker ?? null,
    relationship_type: item.relationship_type ?? null,
    desired_sample_count: item.desired_sample_count ?? item.desired_min_sample_size ?? 0,
    current_sample_count: item.current_sample_count ?? item.current_sample_size ?? 0,
    gap_size: item.gap_size ?? 0,
    why_this_slice_matters: item.why_this_slice_matters ?? item.why_it_matters ?? '',
    suggested_source_type: item.suggested_source_type ?? 'market-events',
    suggested_source_priority: sourcePriorityByType[item.suggested_source_type ?? 'market-events'] ?? ['major-news'],
    search_queries: buildSearchQueries(item),
    source_candidates: [],
    collected_examples: [],
    review_status: 'pending_research',
    reviewer_notes: ''
  };
}

function accessionToArchivePath(cik, accessionNumber, primaryDocument) {
  if (!accessionNumber || !primaryDocument) return null;
  const accessionNoDashes = accessionNumber.replace(/-/g, '');
  const cikNumber = String(parseInt(cik, 10));
  return `https://www.sec.gov/Archives/edgar/data/${cikNumber}/${accessionNoDashes}/${primaryDocument}`;
}

async function fetchJson(url) {
  const response = await fetch(url, {
    headers: {
      'User-Agent': SEC_USER_AGENT,
      'Accept': 'application/json'
    }
  });
  if (!response.ok) {
    throw new Error(`HTTP ${response.status} for ${url}`);
  }
  return await response.json();
}

function mapRecentFilings(submissionsPayload) {
  const recent = submissionsPayload?.filings?.recent;
  if (!recent || !Array.isArray(recent.form)) return [];
  const results = [];
  for (let index = 0; index < recent.form.length; index += 1) {
    const formType = recent.form[index];
    if (!SEC_FORM_PRIORITY.has(formType)) continue;
    results.push({
      formType,
      filingDate: recent.filingDate?.[index] ?? null,
      accessionNumber: recent.accessionNumber?.[index] ?? null,
      primaryDocument: recent.primaryDocument?.[index] ?? null,
      primaryDocDescription: recent.primaryDocDescription?.[index] ?? null,
      reportDate: recent.reportDate?.[index] ?? null
    });
  }
  return results.slice(0, 3);
}

function attachSecCandidates(slice, filings, cik, companyTitle) {
  slice.source_candidates = filings.map((filing, index) => ({
    candidate_id: `${slice.source_gap_key}::sec_candidate_${index + 1}`,
    source_type: 'sec-filings',
    source_name: 'sec_edgar_public_submissions',
    source_url: accessionToArchivePath(cik, filing.accessionNumber, filing.primaryDocument) || `https://data.sec.gov/submissions/CIK${cik}.json`,
    retrieval_status: 'fetched',
    notes: `Candidate ${filing.formType} filing for ${companyTitle || slice.primary_ticker || slice.related_ticker}. Review the filing body before approving ingestion.`
  }));

  slice.collected_examples = filings.map((filing) => ({
    source_name: 'sec_edgar_public_submissions',
    source_record_id: filing.accessionNumber || `${cik}|${filing.formType}|${filing.filingDate}`,
    source_url: accessionToArchivePath(cik, filing.accessionNumber, filing.primaryDocument) || `https://data.sec.gov/submissions/CIK${cik}.json`,
    source_title: filing.primaryDocDescription || `${companyTitle || slice.related_ticker || slice.primary_ticker} ${filing.formType}`,
    source_publisher: 'SEC EDGAR',
    published_at: filing.filingDate ? `${filing.filingDate}T00:00:00Z` : null,
    occurred_at: filing.reportDate ? `${filing.reportDate}T00:00:00Z` : (filing.filingDate ? `${filing.filingDate}T00:00:00Z` : null),
    headline: `${companyTitle || slice.related_ticker || slice.primary_ticker} ${filing.formType} ${filing.primaryDocDescription || 'filing'}`.trim(),
    summary: `Candidate SEC filing gathered from the public submissions feed for ${slice.event_category}. Review the filing body to confirm the event and relationship path.`,
    primary_ticker: slice.primary_ticker || slice.related_ticker,
    related_companies: slice.primary_ticker && slice.related_ticker && slice.primary_ticker !== slice.related_ticker ? [{
      ticker: slice.related_ticker,
      name: slice.related_ticker,
      relationship: slice.relationship_type || 'Related'
    }] : [],
    event_type_hint: slice.event_category,
    sentiment_hint: 'unknown',
    relationship_evidence: slice.relationship_type ? `Review filing body to confirm ${slice.relationship_type} path for ${slice.related_ticker || slice.primary_ticker}.` : null,
    extraction_notes: 'Auto-collected from public SEC submissions metadata only. Use the filing body as the final review source before ingestion.',
    evidence_quote: filing.primaryDocDescription || filing.formType,
    evidence_confidence: 'low',
    duplicate_check_key: `sec_edgar_public_submissions|${filing.accessionNumber || `${cik}|${filing.formType}|${filing.filingDate}`}|${slice.primary_ticker || slice.related_ticker}|${slice.event_category}|${filing.filingDate || 'unknown'}`,
    ready_for_ingestion: false
  }));

  if (slice.collected_examples.length > 0) {
    slice.review_status = 'pending_review';
    slice.reviewer_notes = 'Public SEC submissions metadata collected automatically. Review and confirm filing relevance before copying into the SEC ingestion bundle.';
  } else {
    slice.review_status = 'needs_more_research';
    slice.reviewer_notes = 'No recent public SEC filings matched the allowed forms for this slice.';
  }
}

const researchSlices = planItems
  .filter((item) => item.source_gap_key !== 'price::TTM')
  .map((item) => buildBaseSlice(item));

const secSlices = researchSlices.filter((slice) => slice.suggested_source_type === 'sec-filings');
const secFetchLog = [];
const fetchSupported = typeof fetch === 'function';

if (fetchSupported && secSlices.length > 0) {
  try {
    const companyTickerMapPayload = await fetchJson('https://www.sec.gov/files/company_tickers.json');
    const companyTickerMap = new Map();
    for (const value of Object.values(companyTickerMapPayload || {})) {
      const ticker = String(value?.ticker || '').toUpperCase();
      if (!ticker) continue;
      companyTickerMap.set(ticker, {
        cik: String(value.cik_str).padStart(10, '0'),
        title: value.title || ticker
      });
    }

    for (const slice of secSlices) {
      const lookupTicker = (slice.primary_ticker || slice.related_ticker || '').toUpperCase();
      const company = companyTickerMap.get(lookupTicker);
      if (!company) {
        slice.review_status = 'needs_more_research';
        slice.reviewer_notes = `Ticker ${lookupTicker} was not found in the public SEC ticker mapping feed.`;
        secFetchLog.push({ source_gap_key: slice.source_gap_key, ticker: lookupTicker, status: 'ticker_not_found' });
        continue;
      }

      try {
        const submissions = await fetchJson(`https://data.sec.gov/submissions/CIK${company.cik}.json`);
        const filings = mapRecentFilings(submissions);
        attachSecCandidates(slice, filings, company.cik, company.title);
        secFetchLog.push({
          source_gap_key: slice.source_gap_key,
          ticker: lookupTicker,
          status: filings.length ? 'ok' : 'no_matching_filings',
          filings_collected: filings.length
        });
      } catch (error) {
        slice.review_status = 'needs_more_research';
        slice.reviewer_notes = `SEC fetch failed for ${lookupTicker}: ${error.message}`;
        secFetchLog.push({ source_gap_key: slice.source_gap_key, ticker: lookupTicker, status: 'fetch_error', error: error.message });
      }
    }
  } catch (error) {
    for (const slice of secSlices) {
      slice.review_status = 'needs_more_research';
      slice.reviewer_notes = `SEC public mapping fetch failed: ${error.message}`;
    }
    secFetchLog.push({ status: 'mapping_fetch_error', error: error.message });
  }
} else if (!fetchSupported) {
  for (const slice of secSlices) {
    slice.review_status = 'needs_more_research';
    slice.reviewer_notes = 'Global fetch is unavailable in this n8n runtime. Add an HTTP Request node or upgrade the runtime before auto-collecting SEC metadata.';
  }
  secFetchLog.push({ status: 'fetch_unavailable' });
}

return [
  {
    json: {
      template_metadata: {
        template_name: 'n8n_targeted_research_template',
        schema_version: '1.0.0',
        template_only: false,
        purpose: 'Live n8n research bundle generated from current top-priority StrattonAI backfill slices.',
        generated_from_plan_path: 'reports/targeted_backfill_plan.json',
        generated_at_note: 'Generated inside n8n; copy approved examples into source-specific ingestion bundles before ingestion.'
      },
      workflow_contract: {
        source_of_truth: 'Python and Supabase pipeline',
        n8n_role: [
          'read ranked slice targets',
          'build deterministic search tasks',
          'collect candidate historical examples',
          'document exact source evidence'
        ],
        review_gate: 'All collected_examples stay ready_for_ingestion=false until a human review approves them.',
        handoff_targets: [
          'ingestion/templates/targeted_market_events_template.json',
          'ingestion/templates/targeted_sec_filings_template.json'
        ]
      },
      sec_fetch_summary: {
        fetch_supported: fetchSupported,
        sec_slice_count: secSlices.length,
        log: secFetchLog
      },
      research_slices: researchSlices
    }
  }
];
